1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	
3	type Customer = { yearsWithMHPCO: number };
4	
5	type Scenario = {
6	  customer: Customer;
7	  steps: { op: "quote"; items: Item[] }[];
8	};
9	
10	type ScenarioResult = {
11	  results: { premium: number }[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	
16	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
17	
18	const firstInsuranceSurcharge = (premium: number): number =>
19	  premium * FIRST_INSURANCE_SURCHARGE_RATE;
20	
21	const COMPONENT_PREMIUM = 25;
22	
23	const BASE_PREMIUMS: Record<string, number> = {
24	  sword: 100,
25	  amulet: 60,
26	  staff: 80,
27	  potion: 40,
28	  rune: COMPONENT_PREMIUM,
29	  moonstone: COMPONENT_PREMIUM,
30	};
31	
32	const BLOCK_PREMIUM = 60;
33	
34	const isBlock = (count: number): boolean => count === 3;
35	
36	const countByType = (items: Item[]): Record<string, number> =>
37	  items.reduce<Record<string, number>>((counts, item) => {
38	    counts[item.type] = (counts[item.type] ?? 0) + 1;
39	    return counts;
40	  }, {});
41	
42	const premiumForGroup = (type: string, count: number): number =>
43	  isBlock(count) ? BLOCK_PREMIUM : count * BASE_PREMIUMS[type];
44	
45	const basePremiumFor = (items: Item[]): number =>
46	  Object.entries(countByType(items)).reduce(
47	    (total, [type, count]) => total + premiumForGroup(type, count),
48	    0,
49	  );
50	
51	const roundUpToWholeGold = (amount: number): number => Math.ceil(amount);
52	
53	const surchargeFor = (
54	  items: Item[],
55	  qualifies: (item: Item) => boolean,
56	  rate: number,
57	): number =>
58	  items.reduce(
59	    (total, item) =>
60	      total + (qualifies(item) ? BASE_PREMIUMS[item.type] * rate : 0),
61	    0,
62	  );
63	
64	const CURSE_SURCHARGE_RATE = 0.5;
65	
66	const isCursed = (item: Item): boolean => item.cursed === true;
67	
68	const curseSurchargeFor = (items: Item[]): number =>
69	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
70	
71	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
72	
73	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
74	
75	const isHighlyEnchanted = (item: Item): boolean =>
76	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD;
77	
78	const enchantmentSurchargeFor = (items: Item[]): number =>
79	  surchargeFor(items, isHighlyEnchanted, ENCHANTMENT_SURCHARGE_RATE);
80	
81	const LOYALTY_DISCOUNT_RATE = 0.2;
82	
83	const LOYALTY_YEARS_THRESHOLD = 2;
84	
85	const loyaltyDiscountFor = (customer: Customer, premium: number): number =>
86	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
87	    ? premium * LOYALTY_DISCOUNT_RATE
88	    : 0;
89	
90	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
91	
92	const followUpDiscountFor = (isFollowUp: boolean, premium: number): number =>
93	  isFollowUp ? premium * FOLLOW_UP_DISCOUNT_RATE : 0;
94	
95	const quotePremium = (
96	  customer: Customer,
97	  items: Item[],
98	  isFollowUp: boolean,
99	): number => {
100	  const basePremium = basePremiumFor(items);
101	  return roundUpToWholeGold(
102	    basePremium +
103	      curseSurchargeFor(items) +
104	      enchantmentSurchargeFor(items) +
105	      firstInsuranceSurcharge(basePremium) -
106	      loyaltyDiscountFor(customer, basePremium) -
107	      followUpDiscountFor(isFollowUp, basePremium) +
108	      PROCESSING_FEE,
109	  );
110	};
111	
112	export const runScenario = (scenario: Scenario): ScenarioResult => ({
113	  results: scenario.steps.map((step, index) => ({
114	    premium: quotePremium(scenario.customer, step.items, index > 0),
115	  })),
116	});
